module.exports = "<div id=\"page-wrapper\" class=\"admin-dashboard\">\n    <div class=\"dashboard-header mb-4\">\n        <div class=\"row align-items-center\">\n            <div class=\"col-md-6\">\n                <h2 class=\"m-0\">Admin Dashboard</h2>\n                <p class=\"text-muted small m-0\">System Governance & User Management</p>\n            </div>\n            <div class=\"col-md-6 text-end\">\n                <span class=\"bc-badge bc-badge-verified me-2\">Connected: Mainnet Node</span>\n                <span class=\"text-muted small\">{{account | slice:0:6}}...{{account | slice:-4}}</span>\n            </div>\n        </div>\n    </div>\n\n    <!-- Analytics Cards -->\n    <div class=\"row g-4 mb-5\">\n        <div class=\"col-md-3\">\n            <div class=\"pharma-card stat-card\">\n                <div class=\"d-flex align-items-center justify-content-between mb-3\">\n                    <span class=\"text-muted small fw-bold uppercase\">Total Users</span>\n                    <i class=\"material-icons text-primary\">groups</i>\n                </div>\n                <h3>{{userCount}}</h3>\n                <div class=\"progress mt-3\" style=\"height: 4px;\">\n                    <div class=\"progress-bar bg-primary\" style=\"width: 70%\"></div>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-md-3\">\n            <div class=\"pharma-card stat-card\">\n                <div class=\"d-flex align-items-center justify-content-between mb-3\">\n                    <span class=\"text-muted small fw-bold uppercase\">ETH Balance</span>\n                    <i class=\"material-icons text-warning\">account_balance_wallet</i>\n                </div>\n                <h3>{{balance | slice:0:6}}</h3>\n                <p class=\"text-muted small m-0\">Native Token Assets</p>\n            </div>\n        </div>\n        <div class=\"col-md-6\">\n            <div class=\"pharma-card stat-card highlight-card\">\n                <div class=\"d-flex align-items-center justify-content-between mb-3\">\n                    <span class=\"text-white small fw-bold uppercase\">Smart Contract Address</span>\n                    <i class=\"material-icons text-white\">description</i>\n                </div>\n                <h5 class=\"text-white font-monospace\">{{contractAddress}}</h5>\n                <p class=\"text-white-50 small m-0\">Live on Ethereum Network</p>\n            </div>\n        </div>\n    </div>\n\n    <!-- Shipment & Logs Grid -->\n    <div class=\"row g-4 mb-5\">\n        <div class=\"col-lg-7\">\n            <div class=\"pharma-card h-100\">\n                <div class=\"d-flex justify-content-between align-items-center mb-4\">\n                    <h4 class=\"m-0\">Shipment Monitoring</h4>\n                    <span class=\"badge bg-primary-light text-primary py-2 px-3 rounded-pill small\">6 Active</span>\n                </div>\n                <div class=\"shipment-list\">\n                    <div class=\"shipment-item p-3 bg-light rounded-4 mb-3\" *ngFor=\"let ship of shipmentMonitoring\">\n                        <div class=\"d-flex justify-content-between align-items-center mb-2\">\n                            <span class=\"fw-bold\">ID: {{ship.id}}</span>\n                            <span class=\"bc-badge bc-badge-verified\">{{ship.status}}</span>\n                        </div>\n                        <div class=\"row small text-muted mb-2\">\n                            <div class=\"col-6\">From: {{ship.origin}}</div>\n                            <div class=\"col-6\">To: {{ship.destination}}</div>\n                        </div>\n                        <div class=\"progress\" style=\"height: 6px;\">\n                            <div class=\"progress-bar\" [style.width]=\"ship.timeline\"></div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-5\">\n            <div class=\"pharma-card h-100\">\n                <h4 class=\"mb-4\">Blockchain Logs</h4>\n                <div class=\"log-entry p-3 border-start border-4 border-primary bg-light mb-3\"\n                    *ngFor=\"let log of transactionLogs\">\n                    <div class=\"d-flex justify-content-between align-items-start\">\n                        <div>\n                            <div class=\"fw-bold small\">{{log.type}}</div>\n                            <code class=\"x-small d-block mt-1\">{{log.hash}}</code>\n                        </div>\n                        <span class=\"x-small text-muted\">{{log.time}}</span>\n                    </div>\n                </div>\n                <button class=\"btn btn-outline-secondary w-100 mt-2\">View Full Explorer</button>\n            </div>\n        </div>\n    </div>\n\n    <!-- User Table Section -->\n    <div class=\"pharma-card mb-5\">\n        <div class=\"d-flex justify-content-between align-items-center mb-4\">\n            <h4 class=\"m-0\">Participant Registry</h4>\n            <div class=\"actions\">\n                <button class=\"btn btn-outline-secondary me-2 btn-sm\" (click)=\"refreshList()\">\n                    <i class=\"material-icons align-middle small\">refresh</i> Sync\n                </button>\n                <button class=\"btn btn-primary-pharma btn-sm\" data-toggle=\"modal\" data-target=\"#createuser1\">\n                    <i class=\"material-icons align-middle small\">person_add</i> Register Participant\n                </button>\n            </div>\n        </div>\n\n        <div class=\"alert alert-info py-2 small d-flex align-items-center mb-4\" id=\"divOngoingTransaction\"\n            style=\"display: none\">\n            <i class=\"material-icons me-2\">info</i>\n            <span>Recent Action: <span id=\"linkOngoingTransaction\">None</span></span>\n        </div>\n\n        <div class=\"table-responsive\">\n            <table mat-table [dataSource]=\"dataSource\" class=\"w-100\">\n                <ng-container matColumnDef=\"ethaddress\">\n                    <th mat-header-cell *matHeaderCellDef> Wallet Address </th>\n                    <td mat-cell *matCellDef=\"let element\" class=\"font-monospace small\">\n                        {{element.EthAddress | slice:0:10}}...\n                    </td>\n                </ng-container>\n                <ng-container matColumnDef=\"name\">\n                    <th mat-header-cell *matHeaderCellDef> Full Name </th>\n                    <td mat-cell *matCellDef=\"let element\" class=\"fw-bold\"> {{element.Name}} </td>\n                </ng-container>\n                <ng-container matColumnDef=\"location\">\n                    <th mat-header-cell *matHeaderCellDef> Region </th>\n                    <td mat-cell *matCellDef=\"let element\"> {{element.Location}} </td>\n                </ng-container>\n                <ng-container matColumnDef=\"role\">\n                    <th mat-header-cell *matHeaderCellDef> System Role </th>\n                    <td mat-cell *matCellDef=\"let element\">\n                        <span class=\"bc-badge\"\n                            [ngClass]=\"{'bc-badge-verified': element.Role !== 'NoRole', 'bc-badge-pending': element.Role === 'NoRole'}\">\n                            {{element.Role}}\n                        </span>\n                    </td>\n                </ng-container>\n\n                <tr mat-header-row *matHeaderRowDef=\"displayedColumns\"></tr>\n                <tr mat-row *matRowDef=\"let row; columns: displayedColumns;\"></tr>\n            </table>\n            <mat-paginator [pageSizeOptions]=\"[5, 10, 20]\" showFirstLastButtons class=\"bg-transparent\"></mat-paginator>\n        </div>\n    </div>\n\n    <!-- Registration Modal -->\n    <div class=\"modal fade\" id=\"createuser1\" tabindex=\"-1\">\n        <div class=\"modal-dialog modal-dialog-centered\">\n            <div class=\"modal-content pharma-modal\">\n                <div class=\"modal-header border-0 pb-0\">\n                    <h5 class=\"modal-title fw-bold\">Register New Participant</h5>\n                    <button type=\"button\" class=\"btn-close\" data-dismiss=\"modal\" aria-label=\"Close\"></button>\n                </div>\n                <div class=\"modal-body p-4\">\n                    <p class=\"text-muted small mb-4\">All registrations are permanently written to the blockchain. Ensure\n                        accuracy.</p>\n                    <form [formGroup]=\"registerUser\">\n                        <div class=\"form-group mb-3\">\n                            <label class=\"small fw-bold\">Ethereum Wallet Address</label>\n                            <input type=\"text\" formControlName=\"ethaddress\" class=\"form-control\" placeholder=\"0x...\">\n                        </div>\n                        <div class=\"form-group mb-3\">\n                            <label class=\"small fw-bold\">Full Name / Organization</label>\n                            <input type=\"text\" formControlName=\"name\" class=\"form-control\"\n                                placeholder=\"e.g. Pfizer Inc.\">\n                        </div>\n                        <div class=\"form-group mb-3\">\n                            <label class=\"small fw-bold\">Geographic Location</label>\n                            <div class=\"row g-2\" formGroupName=\"location\">\n                                <div class=\"col\"><input type=\"text\" formControlName=\"latitude\" class=\"form-control\"\n                                        placeholder=\"Lat\"></div>\n                                <div class=\"col\"><input type=\"text\" formControlName=\"longitude\" class=\"form-control\"\n                                        placeholder=\"Long\"></div>\n                            </div>\n                        </div>\n                        <div class=\"form-group mb-4\">\n                            <label class=\"small fw-bold\">Assigned Supply Chain Role</label>\n                            <select class=\"form-control form-select\" formControlName=\"rrole\">\n                                <option *ngFor=\"let rr of Roles\" [value]=\"rr.value\">{{rr.role}}</option>\n                            </select>\n                        </div>\n                        <button type=\"button\" class=\"btn btn-primary-pharma w-100 py-3\" (click)=\"userRegister()\"\n                            [disabled]=\"!registerUser.valid\">\n                            CONFIRM BLOCKCHAIN REGISTRATION\n                        </button>\n                    </form>\n                </div>\n            </div>\n        </div>\n    </div>\n</div>"

