                   <!-- Simplified QR Mockup -->\n                        <div class=\"qr-mock d-flex align-items-center justify-content-center\"\n                            style=\"width: 100px; height: 100px; border: 2px solid #0A3D62;\">\n                            <i class=\"material-icons text-primary h1\">qr_code_2</i>\n                        </div>\n                    </div>\n                </div>\n\n                <div class=\"pharma-card overflow-hidden p-0 mb-4\">\n                    <div class=\"p-4 border-bottom bg-light\">\n                        <h6 class=\"m-0 fw-bold\">Blockchain Metadata</h6>\n                    </div>\n                    <div class=\"p-4 small\">\n                        <div class=\"mb-3\">\n                            <label class=\"text-muted d-block small mb-1\">Contract Address</label>\n                            <code class=\"text-primary\">{{searchBatchId}}</code>\n                        </div>\n                        <div class=\"mb-3\">\n                            <label class=\"text-muted d-block small mb-1\">Network</label>\n                            <span class=\"fw-bold\">Ganache Local Cluster</span>\n                        </div>\n                        <div class=\"mb-0\">\n                            <label class=\"text-muted d-block small mb-1\">Protocol Version</label>\n                            <span class=\"fw-bold\">ERC-SupplyChain v1.0</span>\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <!-- Right Panel: Vertical Timeline -->\n            <div class=\"col-lg-8\">\n                <div class=\"pharma-card p-5\">\n                    <h4 class=\"mb-5 d-flex align-items-center\">\n                        <i class=\"material-icons text-primary me-2\">timeline</i>\n                        Audit Trail Timeline\n                    </h4>\n\n                    <div class=\"pharma-timeline\">\n                        <div class=\"timeline-event\" *ngFor=\"let event of timelineEvents\"\n                            [ngClass]=\"{'active': event.completed}\">\n                            <div class=\"event-indicator\">\n                                <div class=\"dot shadow-sm\">\n                                    <i class=\"material-icons small\">{{event.icon}}</i>\n                                </div>\n                                <div class=\"line\" *ngIf=\"!event.last\"></div>\n                            </div>\n                            <div class=\"event-body pb-5 ps-4\">\n                                <div class=\"d-flex justify-content-between align-items-center mb-1\">\n                                    <h5 class=\"fw-bold m-0\" [ngClass]=\"{'text-primary': event.completed}\">\n                                        {{event.title}}</h5>\n                                    <span class=\"bc-badge bc-badge-verified py-1\"\n                                        *ngIf=\"event.completed\">Verified</span>\n                                </div>\n                                <p class=\"text-muted small mb-3\">{{event.description}}</p>\n\n                                <div class=\"event-meta pharma-card bg-light border-0 p-3\" *ngIf=\"event.completed\">\n                                    <div class=\"row g-3\">\n                                        <div class=\"col-sm-6\">\n                                            <label class=\"text-muted small d-block\">Participant Node</label>\n                                            <span class=\"small font-monospace\">{{event.participant |\n                                                slice:0:15}}...</span>\n                                        </div>\n                                        <div class=\"col-sm-6\">\n                                            <label class=\"text-muted small d-block\">Blockchain Verification</label>\n                                            <span class=\"small font-monospace text-success\">Block #{{event.block ||\n                                                'Pending'}}</span>\n                                        </div>\n                                    </div>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n\n        <!-- Initial State / Loader -->\n        <div *ngIf=\"!batchData && !loading\" class=\"text-center py-5\">\n            <i class=\"material-icons h1 text-muted opacity-25\" style=\"font-size: 80px;\">manage_search</i>\n            <h5 class=\"text-muted\">No audit records displayed. Initiate a trace above.</h5>\n        </div>\n\n        <div *ngIf=\"loading\" class=\"text-center py-5\">\n            <div class=\"spinner-border text-primary\" role=\"status\">\n                <span class=\"visually-hidden\">Loading blockchain data...</span>\n            </div>\n            <p class=\"mt-3 text-muted\">Scanning ledger for Batch ID #{{searchBatchId}}</p>\n        </div>\n    </div>\n</div>"

