module.exports = "<div id=\"page-wrapper\" class=\"transporter-dashboard\">\n    <!-- Dashboard Header -->\n    <div class=\"dashboard-header mb-4\">\n        <div class=\"row align-items-center\">\n            <div class=\"col-md-6\">\n                <h2 class=\"m-0\">Transporter Dashboard</h2>\n                <p class=\"text-muted small m-0\">Secure Transit, Delivery Verification & Fleet Management</p>\n            </div>\n            <div class=\"col-md-6 text-end\">\n                <span class=\"bc-badge bc-badge-verified me-2\">Carrier Verified: {{name}}</span>\n                <span class=\"text-muted small\">{{account | slice:0:6}}...{{account | slice:-4}}</span>\n            </div>\n        </div>\n    </div>\n\n    <!-- Logistics Activity Grid -->\n    <div class=\"row g-4 mb-5\">\n        <div class=\"col-lg-6\">\n            <div class=\"pharma-card h-100\">\n                <h4 class=\"mb-4\">Recent Logistics Actions</h4>\n                <div class=\"activity-timeline\">\n                    <div class=\"activity-item pb-4 border-start border-2 border-light ps-4 position-relative\">\n                        <div class=\"activity-dot bg-success\"></div>\n                        <div class=\"small fw-bold\">Consignment #{{packageCount}} Loaded</div>\n                        <p class=\"text-muted x-small m-0\">Transporter signature verified on-chain</p>\n                    </div>\n                    <div class=\"activity-item pb-4 border-start border-2 border-light ps-4 position-relative\">\n                        <div class=\"activity-dot bg-primary\"></div>\n                        <div class=\"small fw-bold\">Route Optimized</div>\n                        <p class=\"text-muted x-small m-0\">GPS coordinates updated in metadata</p>\n                    </div>\n                    <div class=\"activity-item ps-4 position-relative\">\n                        <div class=\"activity-dot bg-warning\"></div>\n                        <div class=\"small fw-bold\">Audit Request</div>\n                        <p class=\"text-muted x-small m-0\">Manufacturer node requested transit logs</p>\n                    </div>\n                </div>\n            </div>\n        </div>\n        <div class=\"col-lg-6\">\n            <div class=\"pharma-card h-100\">\n                <div class=\"d-flex justify-content-between align-items-center mb-4\">\n                    <h4 class=\"m-0\">Shipment Timeline</h4>\n                    <span class=\"text-primary small fw-bold\">Fulfillment: {{packageCount > 0 ? '75%' : '0%'}}</span>\n                </div>\n                <div class=\"timeline-stepper\">\n                    <div class=\"step-line d-flex justify-content-between position-relative\">\n                        <div class=\"step active text-center\">\n                            <i class=\"material-icons\">inventory</i>\n                            <div class=\"x-small mt-1\">Pickup</div>\n                        </div>\n                        <div class=\"step active text-center\">\n                            <i class=\"material-icons\">local_shipping</i>\n                            <div class=\"x-small mt-1\">Transit</div>\n                        </div>\n                        <div class=\"step text-center text-muted\">\n                            <i class=\"material-icons\">done_all</i>\n                            <div class=\"x-small mt-1\">Delivery</div>\n                        </div>\n                    </div>\n                </div>\n                <!-- Mock QR Scanner Placeholder -->\n                <div class=\"qr-mock-box mt-4 p-4 bg-light rounded-4 text-center border-dashed border-2\">\n                    <i class=\"material-icons h1 m-0 text-muted\">qr_code_scanner</i>\n                    <div class=\"small fw-bold mt-2\">QR SCANNER READY</div>\n                    <p class=\"x-small text-muted mb-0\">Scan batch label to update status</p>\n                </div>\n            </div>\n        </div>\n    </div>\n\n    <!-- Consignment Table Section -->\n    <div class=\"pharma-card\">\n        <div class=\"d-flex justify-content-between align-items-center mb-4\">\n            <h4 class=\"m-0\">Active Shipments (Blockchain Verified)</h4>\n            <div class=\"actions\">\n                <button class=\"btn btn-outline-secondary btn-sm\" (click)=\"transportCount()\">\n                    <i class=\"material-icons align-middle small me-1\">sync</i> Sync Shipments\n                </button>\n            </div>\n        </div>\n\n        <div class=\"table-responsive\">\n            <table mat-table [dataSource]=\"dataSource\" class=\"w-100\">\n                <ng-container matColumnDef=\"txtype\">\n                    <th mat-header-cell *matHeaderCellDef> Service Type </th>\n                    <td mat-cell *matCellDef=\"let element\">\n                        <span class=\"bc-badge\"\n                            [ngClass]=\"{'bc-badge-verified': element.TxType == 0, 'bc-badge-pending': element.TxType != 0}\">\n                            {{element.TxType == 0 ? 'Genesis Transit' : 'Inter-Node Transit'}}\n                        </span>\n                    </td>\n                </ng-container>\n                <ng-container matColumnDef=\"batchid\" sticky>\n                    <th mat-header-cell *matHeaderCellDef> Batch ID </th>\n                    <td mat-cell *matCellDef=\"let element\">\n                        <span class=\"fw-bold text-primary pointer\" data-toggle=\"modal\" data-target=\"#batchidinfo1\"\n                            (click)=\"getPackageTx(element)\">\n                            #{{element.BatchID | slice:0:10}}...\n                        </span>\n                    </td>\n                </ng-container>\n                <ng-container matColumnDef=\"location\">\n                    <th mat-header-cell *matHeaderCellDef> Current Region </th>\n                    <td mat-cell *matCellDef=\"let element\"> {{element.FarmLocation}} </td>\n                </ng-container>\n                <ng-container matColumnDef=\"from\">\n                    <th mat-header-cell *matHeaderCellDef> Genesis Origin </th>\n                    <td mat-cell *matCellDef=\"let element\"> {{element.Supplier | slice:0:8}}... </td>\n                </ng-container>\n                <ng-container matColumnDef=\"to\">\n                    <th mat-header-cell *matHeaderCellDef> Target Facility </th>\n                    <td mat-cell *matCellDef=\"let element\"> {{element.Receiver | slice:0:8}}... </td>\n                </ng-container>\n                <ng-container matColumnDef=\"status\">\n                    <th mat-header-cell *matHeaderCellDef> Chain State </th>\n                    <td mat-cell *matCellDef=\"let element\">\n                        <span class=\"bc-badge\"\n                            [ngClass]=\"{'bc-badge-verified': element.Status == 1, 'bc-badge-pending': element.Status == 0}\">\n                            Stage {{element.Status}}\n                        </span>\n                    </td>\n                </ng-container>\n                <ng-container matColumnDef=\"star\" stickyEnd>\n                    <th mat-header-cell *matHeaderCellDef></th>\n                    <td mat-cell *matCellDef=\"let element\"><i class=\"material-icons text-muted\">more_vert</i></td>\n                </ng-container>\n\n                <tr mat-header-row *matHeaderRowDef=\"displayedColumns\"></tr>\n                <tr mat-row *matRowDef=\"let row; columns: displayedColumns;\"></tr>\n            </table>\n            <mat-paginator [pageSizeOptions]=\"[5, 10, 20]\" showFirstLastButtons class=\"bg-transparent\"></mat-paginator>\n        </div>\n    </div>\n\n    <!-- Batch Detail Modal -->\n    <div class=\"modal fade\" id=\"batchidinfo1\" tabindex=\"-1\">\n        <div class=\"modal-dialog modal-dialog-centered modal-lg\">\n            <div class=\"modal-content pharma-modal\">\n                <div class=\"modal-header border-0 pb-0 p-4 d-flex justify-content-between\">\n                    <h5 class=\"modal-title fw-bold\">Consignment Manifest</h5>\n                    <div id=\"pick-deliver\">\n                        <button type=\"button\" class=\"btn btn-primary-pharma shadow-sm\" *ngIf=\"packageInfo.Status == 0\"\n                            (click)=\"pickPackage(packageInfo.Batch.BatchID,packageInfo.TxType,packageInfo.Batch.BatchID)\">\n                            <i class=\"material-icons align-middle small me-1\">inventory</i> INITIATE PICKUP\n                        </button>\n                        <span class=\"bc-badge bc-badge-verified py-2 px-3\" *ngIf=\"packageInfo.Status > 0\">\n                            PICKUP COMPLETED & SIGNED\n                        </span>\n                    </div>\n                </div>\n                <div class=\"modal-body p-4\">\n                    <div class=\"pharma-card bg-light border-0 p-4\" *ngIf=\"packageInfo.Status > -1\">\n                        <div class=\"row g-4 mb-4\">\n                            <div class=\"col-md-6 border-end\">\n                                <h6 class=\"text-muted uppercase small mb-3\">Batch Details</h6>\n                                <p class=\"mb-1\"><strong>ID:</strong> {{packageInfo.Batch.BatchID}}</p>\n                                <p class=\"mb-1\"><strong>Content:</strong> {{packageInfo.Batch.Description}}</p>\n                                <p class=\"mb-1\"><strong>Qty:</strong> {{packageInfo.Batch.Quantity}} Units</p>\n                            </div>\n                            <div class=\"col-md-6\">\n                                <h6 class=\"text-muted uppercase small mb-3\">Transit Route</h6>\n                                <p class=\"mb-1\"><strong>From:</strong> {{packageInfo.Batch.Supplier | slice:0:15}}...\n                                </p>\n                                <p class=\"mb-1\"><strong>To:</strong> {{packageInfo.Batch.Receiver | slice:0:15}}...</p>\n                                <p class=\"mb-1\"><strong>Region:</strong> {{packageInfo.Batch.FarmLocation}}</p>\n                            </div>\n                        </div>\n                        <div class=\"alert alert-warning small mb-0 d-flex align-items-center\">\n                            <i class=\"material-icons me-2\">security</i>\n                            By initiating pickup, you take legal responsibility of the consignment on the blockchain\n                            ledger.\n                        </div>\n                    </div>\n                </div>\n                <div class=\"modal-footer border-0 p-4\">\n                    <button type=\"button\" class=\"btn btn-secondary w-100\" data-dismiss=\"modal\">Close Manifest</button>\n                </div>\n            </div>\n        </div>\n    </div>\n</div>"

